import urllib.request, struct, math, sys

GPU = "http://127.0.0.1:8093/hidden-embed"
CPU = "http://172.22.160.1:8090/hidden-embed"  # fat-station on Windows host

def post(url, toks, variant=None):
    body = struct.pack("<%dI" % len(toks), *toks)
    h = {"Content-Type": "application/octet-stream"}
    if variant:
        h["X-Variant"] = variant
    req = urllib.request.Request(url, data=body, headers=h)
    d = urllib.request.urlopen(req, timeout=120).read()
    n = len(d)//4
    return list(struct.unpack("<%df" % n, d)), n

def cos(a, b):
    dot = sum(x*y for x,y in zip(a,b))
    na = math.sqrt(sum(x*x for x in a)); nb = math.sqrt(sum(y*y for y in b))
    return dot/(na*nb)

SEQS = [
    [785,6722,315],
    [9707,11,1879],
    [40,1079,264,2421,315,3162,13],
    [785,4124,16599,35835,916,279,15678,5562,13],
    [9707,11,1879,0,2585,525,498,3351,30,358,2776,3730,1632,13],
]

print("seq_len | cpu_dim gpu_dim | cos(pre) | cos(post) | selfcos_pre_post")
allpre=[]; allpost=[]
for toks in SEQS:
    cpu,cn = post(CPU, toks)
    gpre,gn = post(GPU, toks, "pre")
    gpost,_ = post(GPU, toks, "post")
    cpre = cos(cpu, gpre)
    cpost = cos(cpu, gpost)
    pp = cos(gpre, gpost)
    allpre.append(cpre); allpost.append(cpost)
    print("%7d | %7d %7d | %8.5f | %9.5f | %.5f" % (len(toks), cn, gn, cpre, cpost, pp))

print("\nMEAN cos(pre)=%.5f  MEAN cos(post)=%.5f" % (sum(allpre)/len(allpre), sum(allpost)/len(allpost)))
print("MIN  cos(pre)=%.5f  MIN  cos(post)=%.5f" % (min(allpre), min(allpost)))
